var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부인. 잠시 괜찮으십니까?","JPN":"夫人。よろしいですか？","ENG":"Ma'am. Do you have a moment?","TWN":"夫人，打擾你一下？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 들어오시지요.","JPN":"ええ。どうぞ。","ENG":"Yes, come in.","TWN":"好的，請進吧。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오셨군요, 에스텔. 버밍엄 백작가에서의 하루는 썩 괜찮으셨는지요?","JPN":"いらっしゃい、エステル。バーミンガム伯爵家での一日はいかがでしたか？","ENG":"Welcome, Esther. I hope your day at House Birmingham was pleasant?","TWN":"喔，你來了，艾斯特。伯明罕伯爵家的一天過得還不錯嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"식사는 분에 넘칠 정도로 과한 대접을 받았습니다.","JPN":"食事は身に余るほどもてなしていただきました。","ENG":"The meal was more than generous, almost too much.","TWN":"這頓飯真是豐盛得超乎想像。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"목욕도… 넓은 탕을 쓰게 해주셔서 감사할 따름이고요.","JPN":"お風呂も……広い浴槽を使わせていただいてとても感謝しています。","ENG":"And... thank you for the use of the spacious bath.","TWN":"洗澡……能用這麼大的浴池，真是感激不盡。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"다만 건네주신 드레스를 입는 건 힘들겠군요.","JPN":"ただ、あのドレスを着るのはちょっと……","ENG":"However, I don't think I can wear the dress you offered.","TWN":"不過，穿上你給的這件禮服恐怕有些困難呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어머. 프릴 달린 드레스보다 동물 잠옷이 더 좋았을까요?","JPN":"あら。フリル付きのドレスより、動物のパジャマの方が好みだったかしら？","ENG":"Oh my. Would you prefer animal-themed pajamas to a frilly dress?","TWN":"哎呀，比起蕾絲邊的裙子，動物睡衣更好嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"딸이 생기면 입힐 생각으로 남겨둔 드레스가 마침 경에게 어울린다 싶었는데, 이래서야 옷장 공간만 차지하겠어요.\xA0","JPN":"娘が生まれたら着せようと残しておいたドレスが、ちょうど卿に似合うと思ったのですが。これではクローゼットで場所だけ取ってしまうわ。\xA0","ENG":"I'd been saving that dress for a daughter someday, but it looked so fitting on you that I thought I'd pass it along. Now it's just taking up space in the closet.\xA0","TWN":"本來想著如果有女兒的話就給她穿的裙子，沒想到正好適合你。這樣下去只會佔據衣櫃的空間啊。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"마음은 감사하나, 지금은 이 한 벌로 족합니다.","JPN":"お気遣いはありがたいのですが、今はこれ1着で十分です。","ENG":"I appreciate the sentiment, but I'm content with just this one outfit.","TWN":"心意我領了，不過現在這一套就夠了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저를 부르신 이유나 말씀해 주시죠, 부인.","JPN":"なぜ私を呼び出したのですか、夫人。","ENG":"Why did you call for me, ma'am?","TWN":"請告訴我你我來何事吧，夫人。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 이미 예상하셨겠지만 내일 원정에 관한 이야기입니다.","JPN":"ふふ。卿も大方予想はついているでしょう。明日の遠征についてです。","ENG":"Haha. As you might've guessed, it's about tomorrow's expedition.","TWN":"呵呵。雖然你可能已經猜到了，但這是關於明天遠征的故事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"다만, 이쪽은 직접 보는 편이 빠르겠군요.","JPN":"ただ、こちらは直接ご覧になった方が早いでしょうね。","ENG":"Though in this case, it's easier to show you than explain.","TWN":"不過，還是親自看看比較快吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"따라오시지요.","JPN":"行きましょう。","ENG":"Come with me.","TWN":"請跟我來吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"백작가에 전해져 오는 방으로 안내하겠습니다.","JPN":"伯爵家に代々伝わる部屋へとご案内しますわ。","ENG":"I'll take you to a room passed down through House Birmingham.","TWN":"我將帶你前往伯爵家代代相傳的房間。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"여긴 지하임에도 빛이 들어오는 특이한 구조로군요.","JPN":"ここは地下なのに光が差す、独特な構造をしているのですね。","ENG":"Interesting... this chamber's underground, yet it lets in light.","TWN":"這裡雖然是地下，卻有光線照射進來的特殊結構啊。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"분위기를 보면 어떠한 법식을 치르는 곳 같습니다.","JPN":"雰囲気からすると、何か儀礼を行うところのようですが。","ENG":"And by the atmosphere, it looks like a ceremonial space of some kind.","TWN":"從氛圍來看，這裡似乎是舉行某種儀式的地方。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 말씀처럼 이곳은 인도자들의 지혜와 속삭임이 남아있는 장소입니다.","JPN":"ええ。おっしゃるとおり、ここは導き手の知恵とささやきが残されている場所です。","ENG":"Indeed. As you guessed, this is a place where the wisdom and whispers of the Guides linger.","TWN":"是的。正如你所說，這裡是引導者的智慧和低語仍然存在的地方。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그들과 운명으로 얽힌 후계자들은 선조들의 과거를 답습하는 방식으로, 그들의 별빛을 취해왔지요.","JPN":"彼らと運命で結ばれた後継者たちは、先祖の過去をなぞることで星の光を取ってきました。","ENG":"Their successors, bound to them by fate, inherited their starlight by retracing the paths of their ancestors.","TWN":"與他們命運相連的繼承者們通過追隨祖先的過去，汲取了他們的星光。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"인도자라면 기사단의 창립자를 말씀하시는 겁니까?","JPN":"導き手というと、騎士団の創立者のことですか？","ENG":"When you say Guides... do you mean the founders of the Order?","TWN":"引導者是指騎士團的創始人嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 경께서 계신 이 아르카데나 제국이 바로 그녀의 고향입니다.","JPN":"ええ。卿のいる、このアルカデナ帝国こそが彼女の故郷なのです。","ENG":"Yes. The Empire of Arcadena you stand in now was her homeland.","TWN":"是的。你所在的艾爾卡特納帝國正是她的故鄉。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그 증거로… 빛기둥을 향해 손을 뻗어 보시지요.","JPN":"その証拠として……光の柱に向かって手を伸ばしてみてください。","ENG":"As proof... place your hand toward that pillar of light.","TWN":"作為證據……請伸手觸摸光柱吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어떠십니까?","JPN":"いかがですか？","ENG":"What do you feel?","TWN":"……怎麼樣？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"낯설지 않은 감각입니다.","JPN":"知っている感覚です。","ENG":"It's a familiar sensation.","TWN":"這是一種熟悉的感覺。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이건, 마치 버고 소드를 쥔 것 같군요.","JPN":"これは、まるでヴァルゴソードを手に取っているようですね。","ENG":"It feels like holding the Virgo Sword.","TWN":"這感覺就像握住了布林加夫之劍。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"무구에 담긴 별빛은 전부 인도자의 힘으로부터 비롯된 것이니, 말씀하신 것이 마냥 다르지는 않습니다.","JPN":"武具に込められた星の光はすべて導き手の力から来たものです。おっしゃることはあながち間違っていません。","ENG":"All starlight embedded in Armaments ultimately comes from the power of the Guide, so it's not a stretch to say that.","TWN":"武器中蘊含的星光全都源自引導者的力量，所以你所說的並不完全不同。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"본디 별의 무구란 황도궁이 떠오른 관측점에서 특수한 성질을 띄게 된 인도자의 별빛.","JPN":"本来星の武具とは、黄道十二星座が浮かび上がった観測点において特殊な性質を持つようになった、導き手の星の光。","ENG":"By nature, a Star Armament is forged from the Star Guide's starlight, which takes on special properties at the point of observation where the Zodiac rises.","TWN":"原本星之武具是十二宮升起時在觀測點上具有特殊性質的引導者的星光。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그것을 무구 안에 담아 벼려낸, 고유무장을 뜻하니까요.","JPN":"それを武具の中に込めて鍛えた固有武装のことですから。","ENG":"That starlight is then imbued into the weapon, creating what we call Unique Gear.","TWN":"那是指將其置於武器中淬火而成的專屬武裝。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"고유무장이라니… 별의 무구가 본디 특정 카운터 전용으로 만들어졌다는 겁니까?","JPN":"固有武装……星の武具が本来は特定カウンターの専用武器として作られたということですか？","ENG":"Unique Gear...? Are you saying these were originally made for specific Counters?","TWN":"專屬裝備……星之武具本來就是為特定制裁者製作的嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 아마 경께서 알고 계시는 의미와는 사뭇 다를 겁니다.","JPN":"ふふ。おそらくは卿がご存じの意味とはまったく異なるでしょうね。","ENG":"Haha. Likely not in the sense you're thinking.","TWN":"呵呵，恐怕與你所知道的意義截然不同。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"번뇌를 다스리는 용검 라르고. 현세와 명계를 잇는 부활의 지팡이.","JPN":"煩悩を鎮める龍剣ラルゴ。現世と冥界を繋げる復活の杖。","ENG":"There's Dragonsword Largo, the blade that governs anguish. And the Staff of Resurrection that bridges life and death.","TWN":"掌控煩惱的龍劍雷諾可。連接現世與冥界的復活之杖。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제국의 명가에 내려져 오는 마검 사파이어 프리즌과 마창 레나투스.","JPN":"帝国の名家に受け継がれている魔剣サファイアプリズンと魔槍レナトゥス。","ENG":"The Evil Sword Sapphire Prison and Evil Spear Renatus, passed down through imperial houses.","TWN":"帝國名門代代相傳的魔劍藍寶稜鏡和魔槍雷納圖斯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그리고… 인도자가 만들어낸 별의 무구까지.","JPN":"そして……導き手が作り出した星の武具。","ENG":"And of course... the Star Armaments forged by the Guide herself.","TWN":"還有……引導者創造的星之武具。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제국의 고유무장이란 무구의 운명과 직간접적으로 얽힌 적합자들을 위한 무장이자.","JPN":"帝国の固有武装とは、武具の運命と直接的に、または間接的に結ばれた適合者のための武装であり。","ENG":"Unique Gear of the Empire are weapons deeply linked, whether directly or indirectly, to those fated to wield them.","TWN":"帝國的專屬武裝，是與武具的命運直接或間接交錯在一起之人武器。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"역사를 지킨 영웅들이 남긴 제국의 비보입니다.","JPN":"歴史を守った英雄たちが残した帝国の秘宝なのです。","ENG":"And they're treasured relics left behind by the heroes who protected our history.","TWN":"同時也是守護歷史的英雄留下的帝國寶藏。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"강력한 힘을 동반하는 만큼 사용에 큰 제약이 따르는 무장이기도 하지요.","JPN":"その力が強力である半面、使用には大きな制約が伴う武装でもあります。","ENG":"Of course, with great power comes heavy limitations.","TWN":"伴隨著強大的力量，這種武裝的使用也有很大的限制。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그리 말씀하신들, 이제껏 별의 무구를 사용하는데 제약이 걸린 기사는 없었습니다.","JPN":"そう言われましても、今まで星の武具を使う時に制約を受けた騎士の話は聞いたことがありません。","ENG":"Even so, I've never heard of a knight being restricted from using the Star Armament before.","TWN":"即便如此，至今為止還沒有騎士在使用武器時受到限制。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당연합니다. 본디 별의 무구에 담긴 별빛은 하나였으니까요.","JPN":"当然です。本来星の武具に込められた星の光は1つだったのですから。","ENG":"Naturally. The starlight within the Armaments was once one and the same.","TWN":"當然了。原本蘊含在星之武具中的星光本就是一體的。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그것이 여러 형태로 나뉜 지금, 제약이라고 할만한 것이 어디 있겠습니까?","JPN":"それが複数に分けられている現在では、制約などあるわけがありません。","ENG":"But now that it's been split into many forms, how could any real limitation remain?","TWN":"如今它分成了多種形態，還有什麼能稱之為限制呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"별의 무구에 담긴 별빛이 하나였다고요?","JPN":"星の武具に込められた星の光が1つだった？","ENG":"The starlight in the Armaments was originally one?","TWN":"星之武具中蘊含的星光只有一個嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 참고삼아 옛 선조들이 남긴 구전을 경께 읊어드리자면…….","JPN":"ええ。参考として先祖が残した伝承を卿にお聞かせしますと……","ENG":"Yes. If I may quote the oral traditions passed down by our ancestors...","TWN":"是的。作為參考，我給你吟誦一下古代先祖留下的傳說……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세상에 암흑이 창궐한 이후, 초대 인도자는 무구를 벼려내어 세상을 구원하였으나.","JPN":"世界に暗黒が蔓延した後、初代の導き手は武具を鍛え世界を救いましたが。","ENG":"After darkness engulfed the world, the first Guide forged an Armament and saved the land.","TWN":"在黑暗肆虐的世界中，初代引導者鍛造了武器拯救了世界。"},"stage":{"bg":"MS_1119","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"큰 피해가 초래됨에 하나의 빛으로는 세상을 온전히 비출 수 없음을 깨달았습니다.","JPN":"大被害がもたらされると、1つの光だけでは世界を十分に照らすことができないことに気づきました。","ENG":"But seeing the devastation it caused, she realized one light alone could not illuminate the whole world.","TWN":"在遭受巨大損失後，她意識到單憑一道光無法照亮整個世界。"},"stage":{"bg":"MS_1119","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"때문에 그녀는 무구 안에 담긴 별빛을 열두 개로 나누어 하늘에 광명을 새겼고…….","JPN":"そのため、彼女は武具に宿る星の光を12個に分け、空に光明を刻み……","ENG":"So she split the starlight held within the Armament into twelve, engraving their radiance into the sky...","TWN":"因此，她將武器中的星光分成十二份，銘刻在天空中……"},"stage":{"bg":"MS_1119","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당대의 인도자들이 이러한 광명을 이용하여 만들어낸 것이 별의 무구지요.","JPN":"当代の導き手たちがこのような光明を利用して作り出したのが星の武具なのです。","ENG":"And the Star Armaments we know were made by later Guides who harnessed that radiance.","TWN":"當代的引導者們利用這種光芒創造出了星之武具。"},"stage":{"bg":"MS_1119","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"인도자의 전승에서 엇비슷한 문구를 본 기억은 있습니다.","JPN":"導き手の伝承でそれと似た文章を見た覚えはあります。","ENG":"I remember reading something similar in the legends of the Guide.","TWN":"我記得在引導者的傳承中看到過類似的句子。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"하지만 그래서야, 기사단의 근원인 열두 무구가 불완전하다는 듯 들리는군요.","JPN":"ですが、それでは騎士団の根源である12武具が不完全だという意味に聞こえるのですが。","ENG":"But if that's true, doesn't that mean the twelve founding Armaments of the Order are incomplete?","TWN":"但是這樣一來，聽起來好像騎士團的根源——十二聖遺物是不完整的。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"나누어졌다 한들 그 안에 담긴 별빛이 어떤 가능성을 품을지는 사용자에게 달렸습니다.","JPN":"分けられたとしても、その中に込められた星の光がどのような可能性を持つかは使用者次第です。","ENG":"Divided or not, what potential lies within that starlight depends entirely on its wielder.","TWN":"即使分開，其中蘊含的星光能帶來什麼樣的可能性，取決於使用者。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당장은 제국에 가라앉은 어둠을 몰아내기 위해 태초의 별빛이 필요할 뿐이지요.","JPN":"今は帝国に淀む闇を払うため、太古の星の光が必要なだけ。","ENG":"What we need right now is the primordial starlight to drive out the darkness that plagues the Empire.","TWN":"目前只需要太初的星光來驅散帝國的黑暗。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"태초의 별빛이 필요하다…….","JPN":"太古の星の光が必要……","ENG":"The primordial starlight...","TWN":"需要初始的星光……"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"결과적으로 열두 무구를 모으는 것이 부인의 목적이라는 뜻이군요.","JPN":"つまり、12武具を集めることが夫人の目的だということですね。","ENG":"So your goal is to gather all twelve Armaments.","TWN":"結果就是，夫人的目的是收集十二聖遺物。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 경께서 명석한 나머지 제 설명의 필요성이 줄어들었네요.","JPN":"ふふ。聡明な卿のおかげで、私が説明する手間が省けました。","ENG":"Haha. You're sharp enough that I don't need to explain further.","TWN":"呵呵。你如此聰明，讓我不需要多做解釋了呢。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"오전에는 도움을 청했으나 쉽지 않은 여정이 될 것임은 확실합니다.","JPN":"午前中に協力をお願いしましたが、きっと旅路には困難が伴うでしょう。","ENG":"Though I did ask for your help this morning, it won't be an easy journey.","TWN":"上午雖然請求了幫助，但可以肯定的是，這將是一段不易的旅程。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"경께서 원하신다면 백작령에 남아 있으셔도 무방해요.","JPN":"卿がお望みなら、伯爵領に残ってもいいのですよ。","ENG":"If you wish, you're welcome to remain here in the County.","TWN":"如果你願意，可以留在伯爵領地。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"이제 와서 남는다고 말하는 것도 이상하다고 생각합니다.","JPN":"今更残ると言うのもおかしいと思います。","ENG":"It would feel wrong to turn back now.","TWN":"現在說留下來也很奇怪。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아직, 전 부인께서 말씀하신 진실에 다다르지 못했으니까요.","JPN":"まだ、私は夫人の言う真実にたどり着いていないのですから。","ENG":"Not when I still haven't reached the truth you spoke of.","TWN":"畢竟，我還沒有觸及夫人所說的真相。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"후후. 경께서 그리 말하실 줄 알았습니다.","JPN":"ふふ。卿ならそうおっしゃると思いました。","ENG":"Haha. I knew you'd say that.","TWN":"我就知道你會這麼說。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"내일 해가 뜨는 대로 병사들을 모아 출발할 것입니다.","JPN":"明日、夜が明けたら兵士を集めて出発します。","ENG":"At sunrise tomorrow, we'll gather the soldiers and depart.","TWN":"明天一早我們就集合士兵出發。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"큰 싸움을 앞둔 상황이니 푹 쉬어 두시지요.","JPN":"大規模な戦いとなるでしょうから、よく休んでおくことです。","ENG":"A fierce battle lies ahead. Get some rest while you can.","TWN":"大戰在即，還是好好休息一下吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};